using BotFramework.Discord.Commands;using BotFramework.Discord.Routing;using Games.Football.Application.Services;
namespace Games.Football.Discord;
public sealed class FootballDiscordHandler(IFootballService service):IDiscordMessageHandler{public bool CanHandle(DiscordMessageContext c)=>DiscordCommand.Is(c,"football");public async Task HandleAsync(DiscordMessageContext c){var p=DiscordCommand.Parts(c);if(p.Length!=2||!int.TryParse(p[1],out var amount)||amount<=0){await DiscordCommand.ReplyAsync(c,"Использование: `football <ставка>`");return;}var u=DiscordCommand.UserId(c);var s=DiscordCommand.ScopeId(c);var src=DiscordCommand.SourceId(c);var n=DiscordCommand.DisplayName(c);_ = await service.PlaceBetAsync(u,n,s,amount,src,c.CancellationToken);var face=DiscordCommand.RandomFace(1,5);var r=await service.ThrowAsync(u,n,s,face,src,c.CancellationToken);await DiscordCommand.ReplyResultAsync(c,r,"Football: "+face);}}
public static class FootballDiscordModule{public static IServiceCollection AddFootballDiscord(this IServiceCollection s)=>s.AddScoped<IDiscordMessageHandler,FootballDiscordHandler>();}
